663:     /**
664:      * Returns the cleanup time for a window, which is {@code window.maxTimestamp +
665:      * allowedLateness}. In case this leads to a value greater than {@link Long#MAX_VALUE} then a
666:      * cleanup time of {@link Long#MAX_VALUE} is returned.
667:      *
668:      * @param window the window whose cleanup time we are computing.
669:      */
670:     private long cleanupTime(W window) {
671:         if (windowAssigner.isEventTime()) {
672:             long cleanupTime = window.maxTimestamp() + allowedLateness;
673:             return cleanupTime >= window.maxTimestamp() ? cleanupTime : Long.MAX_VALUE;
674:         } else {
675:             return window.maxTimestamp();
676:         }
677:     }
