50: /**
51:  * A {@link WindowOperator} that also allows an {@link Evictor} to be used.
52:  *
53:  * <p>The {@code Evictor} is used to remove elements from a pane before/after the evaluation of
54:  * {@link InternalWindowFunction} and after the window evaluation gets triggered by a {@link
55:  * org.apache.flink.streaming.api.windowing.triggers.Trigger}.
56:  *
57:  * @param <K> The type of key returned by the {@code KeySelector}.
58:  * @param <IN> The type of the incoming elements.
59:  * @param <OUT> The type of elements emitted by the {@code InternalWindowFunction}.
60:  * @param <W> The type of {@code Window} that the {@code WindowAssigner} assigns.
61:  */
62: @Internal
63: public class EvictingWindowOperator<K, IN, OUT, W extends Window>
64:         extends WindowOperator<K, IN, Iterable<IN>, OUT, W> {
65: 
66:     private static final long serialVersionUID = 1L;
67: 
68:     // ------------------------------------------------------------------------
69:     // these fields are set by the API stream graph builder to configure the operator
70: 
71:     private final Evictor<? super IN, ? super W> evictor;
72: 
73:     private final StateDescriptor<? extends ListState<StreamRecord<IN>>, ?>
74:             evictingWindowStateDescriptor;
75: 
76:     // ------------------------------------------------------------------------
77:     // the fields below are instantiated once the operator runs in the runtime
78: 
79:     private transient EvictorContext evictorContext;
80: 
81:     private transient InternalListState<K, W, StreamRecord<IN>> evictingWindowState;
82: 
83:     // ------------------------------------------------------------------------
84: 
85:     public EvictingWindowOperator(
86:             WindowAssigner<? super IN, W> windowAssigner,
87:             TypeSerializer<W> windowSerializer,
88:             KeySelector<IN, K> keySelector,
89:             TypeSerializer<K> keySerializer,
90:             StateDescriptor<? extends ListState<StreamRecord<IN>>, ?> windowStateDescriptor,
91:             InternalWindowFunction<Iterable<IN>, OUT, K, W> windowFunction,
92:             Trigger<? super IN, ? super W> trigger,
93:             Evictor<? super IN, ? super W> evictor,
94:             long allowedLateness,
95:             OutputTag<IN> lateDataOutputTag) {
96: 
97:         super(
98:                 windowAssigner,
99:                 windowSerializer,
100:                 keySelector,
101:                 keySerializer,
102:                 null,
103:                 windowFunction,
104:                 trigger,
105:                 allowedLateness,
106:                 lateDataOutputTag);
107: 
108:         this.evictor = checkNotNull(evictor);
109:         this.evictingWindowStateDescriptor = checkNotNull(windowStateDescriptor);
110:     }
111: 
112:     @Override
113:     public void processElement(StreamRecord<IN> element) throws Exception {
114:         final Collection<W> elementWindows =
115:                 windowAssigner.assignWindows(
116:                         element.getValue(), element.getTimestamp(), windowAssignerContext);
117: 
118:         // if element is handled by none of assigned elementWindows
119:         boolean isSkippedElement = true;
120: 
121:         final K key = this.<K>getKeyedStateBackend().getCurrentKey();
122: 
123:         if (windowAssigner instanceof MergingWindowAssigner) {
124:             MergingWindowSet<W> mergingWindows = getMergingWindowSet();
125: 
126:             for (W window : elementWindows) {
127: 
128:                 // adding the new window might result in a merge, in that case the actualWindow
129:                 // is the merged window and we work with that. If we don't merge then
130:                 // actualWindow == window
131:                 W actualWindow =
132:                         mergingWindows.addWindow(
133:                                 window,
134:                                 new MergingWindowSet.MergeFunction<W>() {
135:                                     @Override
136:                                     public void merge(
137:                                             W mergeResult,
138:                                             Collection<W> mergedWindows,
139:                                             W stateWindowResult,
140:                                             Collection<W> mergedStateWindows)
141:                                             throws Exception {
